#include <stdio.h>

int digitSum(int x) {
    int s = 0;
    while (x > 0) {
        s += x % 10;
        x /= 10;
    }
    return s;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int chefScore = 0, mortyScore = 0;
        for (int i = 0; i < N; ++i) {
            int A, B; scanf("%d %d", &A, &B);
            int sa = digitSum(A);
            int sb = digitSum(B);
            if (sa > sb) chefScore++;
            else if (sb > sa) mortyScore++;
            else { chefScore++; mortyScore++; }
        }
        if (chefScore > mortyScore) printf("0 %d\n", chefScore);
        else if (mortyScore > chefScore) printf("1 %d\n", mortyScore);
        else printf("2 %d\n", chefScore);
    }
    return 0;
}

