code.Python3:
#!/usr/bin/env python3
import sys

def digit_sum(x: int) -> int:
    s = 0
    while x:
        s += x % 10
        x //= 10
    return s

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        chef = morty = 0
        for _ in range(N):
            A = int(next(it)); B = int(next(it))
            sa = digit_sum(A)
            sb = digit_sum(B)
            if sa > sb:
                chef += 1
            elif sb > sa:
                morty += 1
            else:
                chef += 1
                morty += 1
        if chef > morty:
            out_lines.append(f"0 {chef}")
        elif morty > chef:
            out_lines.append(f"1 {morty}")
        else:
            out_lines.append(f"2 {chef}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

